import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
    const [jsonPath, setJsonPath] = useState("");
    const [jsonPathResult, setJsonPathResult] = useState(null);
    const [imagePath, setImagePath] = useState("");
    const [imageUrl, setImageUrl] = useState("");

    const backendUrl = "http://localhost:8000"; // Backend base URL

    const axiosInstance = axios.create({
        baseURL: backendUrl,
    });

    const handleFetchImage = async () => {
        if (!imagePath) {
            alert("Please enter an image path.");
            return;
        }

        try {
            const response = await axiosInstance.get("/fetch-image", {
                params: { path: imagePath },
                responseType: "arraybuffer",
            });

            const imageBlob = new Blob([response.data], {
                type: response.headers["content-type"],
            });
            setImageUrl(URL.createObjectURL(imageBlob));
        } catch (error) {
            console.error("Error fetching image:", error);
            alert("Failed to fetch the image.");
        }
    };

    return (
        <div className="App">
            <header>
                <h1>EXIF VIEWER</h1>
            </header>
            <div className="container">
                <hr />

                <section>
                    <h2>Fetch Image</h2>
                    <div className="form-group">
                        <label>Enter Image Path:</label>
                        <input
                            type="text"
                            value={imagePath}
                            onChange={(e) => setImagePath(e.target.value)}
                            placeholder="200/300"
                        />
                        <button onClick={handleFetchImage}>Fetch</button>
                    </div>
                    {imageUrl && (
                        <div className="result">
                            <img
                                src={imageUrl}
                                alt="{imageU}"
                                style={{ maxWidth: "100%", height: "auto" }}
                            />
                        </div>
                    )}
                </section>


            </div>
        </div>
    );
}

export default App;
